const httpRequest = this.helpers.httpRequest.bind(this);

async function loadDirectoryFromSupabase(code) {
  if (!supabaseUrl || !serviceKey) return null;

  const url = `${supabaseUrl}/rest/v1/directory_channels?code=eq.${encodeURIComponent(code)}&select=*`;

  try {
    const response = await httpRequest({
      method: 'GET',
      url,
      headers: {
        apikey: serviceKey,
        Authorization: `Bearer ${serviceKey}`,
        Accept: 'application/json'
      },
      json: true,
      resolveWithFullResponse: true,
      simple: false,
    });

    const statusCode = response.statusCode || response.status || 200;
    const body = response.body !== undefined ? response.body : response;

    if (statusCode >= 400) {
      return {
        _lookup_error: true,
        _lookup_status: statusCode,
        _lookup_message: typeof body === 'string' ? body : JSON.stringify(body)
      };
    }

    const rows = typeof body === 'string' ? JSON.parse(body || '[]') : body;
    return Array.isArray(rows) && rows.length ? rows[0] : null;
  } catch (err) {
    return {
      _lookup_error: true,
      _lookup_status: 500,
      _lookup_message: err.message || String(err)
    };
  }
}

let row = await loadDirectoryFromSupabase(channel);
let source = 'supabase';

if (!row || row._lookup_error) {
  const fallback = fallbackDirectories[channel];
  if (fallback) {
    row = {
      code: channel,
      name: fallback.name,
      country: fallback.country,
      email_to: fallback.email,
      submission_type: fallback.submission_type || 'email',
      is_active: true,
      website_url: fallback.website_url || null,
      form_url: fallback.form_url || null,
      requires_login: false,
      requires_manual_review: true,
      requires_paid_plan: false,
      api_available: false,
      notes: null,
      _fallback_subject: fallback.subject,
      _fallback_language: fallback.language
    };
    source = 'fallback';
  }
}

if (!row) {
  return [{ json: {
    ...data,
    channel,
    directory_name: channel,
    directory_source: 'not_found',
    email_to: '',
    email_subject: '',
    email_language: 'pt-BR',
    email_skip: true,
    skip_status: 'error',
    skip_status_code: 404,
    email_error: `Diretório ${channel} não encontrado em directory_channels`,
    raw_directory_config: {}
  }}];
}

if (row._lookup_error) {
  return [{ json: {
    ...data,
    channel,
    directory_name: channel,
    directory_source: 'lookup_error',
    email_to: '',
    email_subject: '',
    email_language: 'pt-BR',
    email_skip: true,
    skip_status: 'error',
    skip_status_code: row._lookup_status || 500,
    email_error: `Erro ao consultar directory_channels: ${row._lookup_message || 'sem detalhe'}`,
    raw_directory_config: row
  }}];
}

const active = row.is_active !== false;
const submissionType = String(row.submission_type || 'manual').toLowerCase();
const emailTo = row.email_to || row.email || '';
const directoryName = row.name || channel;
const language = row.country === 'BR' ? 'pt-BR' : 'en-US';
const defaultSubject = language === 'pt-BR'
  ? `Solicitação de cadastro/atualização - ${data.name}`
  : `Business listing request - ${data.name}`;
const subjectTemplate = row.email_subject || row.subject || row._fallback_subject;
const emailSubject = subjectTemplate ? String(subjectTemplate).replace('{name}', data.name) : defaultSubject;

if (!active) {
  return [{ json: {
    ...data,
    channel,
    directory_name: directoryName,
    directory_country: row.country,
    directory_source: source,
    directory_submission_type: submissionType,
    email_to: '',
    email_subject: '',
    email_language: language,
