  raw_directory_config: row
}}];

const data = $input.first().json;
if (data.email_skip) return [{ json: data }];

function br(v){ return String(v || '').replace(/\n/g, '<br>'); }
const isPt = data.email_language === 'pt-BR';
const title = isPt ? 'Solicitação de Cadastro/Atualização' : 'Business Listing Request';
const intro = isPt
  ? 'Solicito a inclusão ou atualização dos dados da seguinte empresa em sua plataforma:'
  : 'I would like to request the inclusion or update of the following business information on your platform:';
const signoff = isPt ? 'Atenciosamente' : 'Best regards';

