        source: originalData.directory_source || null
      },
      created_at: new Date().toISOString()
    }
  }];
}

return [{
  json: {
    ...originalData,
    channel: originalData.current_channel,
    status: 'sent',
    status_code: 200,
    message: `Email sent to ${originalData.directory_name}`,
    duration_ms: duration,
    raw_response: {
      gmail_response: input,
      directory_config: originalData.raw_directory_config || {},
      submission_type: originalData.directory_submission_type || null,
      source: originalData.directory_source || null
    },
    created_at: new Date().toISOString()
  }
}];

// Apenas reduz o objeto para a tabela antiga sync_logs.
const data = $input.first().json;
return [{
  json: {
    sync_id: data.sync_id,
    profile_id: data.profile_id || data.location_id || data.company_id || data.id,
    channel: data.channel || data.current_channel,
    status: data.status,
    status_code: data.status_code,
    message: data.message,
    duration_ms: data.duration_ms,
    created_at: data.created_at || new Date().toISOString(),
    // Mantém os campos novos para o próximo nó.
    company_id: data.company_id,
    location_id: data.location_id,
    user_id: data.user_id,
    channel_code: data.channel || data.current_channel,
    raw_response: data.raw_response || {}
  }
}];

// Resposta final compatível com o frontend da Vercel.
// Considera sucesso somente para status de publicação/envio real.

let processedItems = [];

try {
  processedItems = $items('Function - Prepare Sync Logs').map(item => item.json || {});
} catch (error) {
  processedItems = $input.all().map(item => item.json || {});
}

const original = $('Function - Validate Input').first().json || {};
const results = {};

for (const item of processedItems) {
  const channel = item.channel_code || item.channel || item.current_channel;
  if (!channel) continue;

  results[channel] = {
    status: item.status || 'error',
    statusCode: item.status_code || item.statusCode || 400,
    message: item.message || `Processed ${channel}`,
    durationMs: item.duration_ms || item.durationMs || null
  };
}

const resultValues = Object.values(results);
const success = resultValues.length > 0 && resultValues.every(item =>
  item.status === 'success' ||
  item.status === 'sent' ||
  item.status === 'ok'
);

return [
  {
    json: {
      success,
      sync_id: original.sync_id || processedItems[0]?.sync_id || `sync_${Date.now()}_${Math.random().toString(36).slice(2)}`,
      timestamp: new Date().toISOString(),
      total_channels: resultValues.length,
      results
    }
  }
];
